{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental structural change to the aggregate root, not a simple field addition. It redefines what a Shipment *is* — from a single delivery unit to a delivery group — and has cascading implications across bounded contexts, external integrations, and operational workflows.",
    "bounded_context": "Shipment Management / Delivery Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A logistical unit representing the transport of goods from an origin to one or more destinations. Under the new model, a Shipment is a container for a delivery group, not a single point-to-point delivery." },
      { "term": "Recipient", "definition": "A party who receives goods. Identified by name, address, phone number, and (newly) delivery preferences. A Recipient belongs to exactly one Shipment." },
      { "term": "Delivery Preference", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, safe-place authorization, signature requirements). New concept introduced with multi-recipient support." },
      { "term": "Primary Recipient", "definition": "UNDEFINED — the spec does not clarify whether one recipient in a multi-recipient shipment is designated as primary. This is a critical ambiguity." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a Shipment. Under multi-recipient, it is ambiguous whether this is a single aggregate status or derived from per-recipient delivery statuses." },
      { "term": "Delivery Attempt", "definition": "A courier's effort to deliver to a specific recipient. Under multi-recipient, attempts are per-recipient, not per-shipment." },
      { "term": "Proof of Delivery (POD)", "definition": "Evidence that goods were delivered. Under multi-recipient, POD must be captured per-recipient, not per-shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment with no recipient is logically and physically meaningless — there is no destination. This is a data integrity constraint that, if violated, produces an undeliverable and unroutable record.",
      "testable_assertion": "Creating or updating a Shipment with an empty Recipients collection must be rejected at the domain level."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum identifiers required to route, deliver, and contact a recipient. Missing any one makes delivery operationally impossible and violates the existing data contract.",
      "testable_assertion": "Adding a Recipient with a null/empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "All existing single-recipient shipments must remain valid and queryable under the new model without data loss or behavioral change.",
      "invariant": true,
      "invariant_justification": "2 million production records represent real-world obligations. Migration must preserve semantic equivalence — the single recipient becomes a collection of one. Any data corruption or loss is a state integrity violation.",
      "testable_assertion": "After migration, every existing shipment must return exactly one recipient with identical name, address, and phone as before."
    },
    {
      "id": "BR-4",
      "rule": "Delivery preferences are per-Recipient, not per-Shipment.",
      "invariant": true,
      "invariant_justification": "The spec explicitly states 'each Recipient can have different delivery preferences.' Storing preferences at the shipment level would violate the stated business requirement and conflate distinct recipient needs.",
      "testable_assertion": "Two recipients on the same shipment can have different delivery preference values, and each recipient's preferences are independently retrievable."
    },
    {
      "id": "BR-5",
      "rule": "Delivery preferences are optional for each Recipient.",
      "invariant": false,
      "invariant_justification": "The spec says recipients 'can have' different preferences, implying optionality. Existing recipients have no preferences — forcing a default would be a policy decision, not a physical constraint.",
      "testable_assertion": "A Recipient with null/empty delivery preferences is valid. Existing migrated recipients have no delivery preferences set."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format until explicitly migrated.",
      "invariant": false,
      "invariant_justification": "This is a contractual/policy obligation, not a state integrity constraint. Partners could be migrated on a timeline, but breaking their integration is a business risk, not a data corruption issue.",
      "testable_assertion": "For shipments with one recipient, the partner API payload is byte-identical to the current format. For multi-recipient shipments, the API adapter produces a well-defined transformation (to be specified)."
    },
    {
      "id": "BR-7",
      "rule": "A Recipient's address must be unique within a single Shipment.",
      "invariant": false,
      "invariant_justification": "Delivering to the same address twice under the same shipment is likely a data entry error but could be valid in edge cases (e.g., two different people at the same address). This is a policy guard, not a physical constraint. Flagged as ambiguity.",
      "testable_assertion": "If enforced: adding two recipients with the same address to a shipment is rejected. If not enforced: a warning is surfaced but the operation succeeds."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new shipment is being created",
      "when": "The creator provides two or more recipients with valid name, address, phone, and distinct delivery preferences",
      "then": "The shipment is created successfully with all recipients and their individual preferences persisted"
    },
    {
      "id": "AC-2",
      "given": "An existing production shipment with one recipient (pre-migration)",
      "when": "The data migration runs",
      "then": "The shipment now has a Recipients collection containing exactly one entry with the original name, address, phone, and null delivery preferences"
    },
    {
      "id": "AC-3",
      "given": "A shipment with three recipients exists",
      "when": "An external partner API requests shipment data",
      "then": "The API adapter returns data in the contracted format without error (transformation strategy TBD per escalation)"
    },
    {
      "id": "AC-4",
      "given": "A shipment creation request with zero recipients",
      "when": "The request is processed",
      "then": "The system rejects it with a validation error — shipment is not created"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient shipment where recipient A has been delivered and recipient B has not",
      "when": "The shipment status is queried",
      "then": "The system returns a status that accurately reflects the partial delivery state (status model TBD per escalation)"
    },
    {
      "id": "AC-6",
      "given": "A shipment with one recipient and no delivery preferences",
      "when": "The shipment is processed for delivery",
      "then": "The system uses default delivery behavior — delivery preferences are optional, not required"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient shipment where one recipient refuses delivery",
      "expected_behavior": "The refused recipient gets a 'refused' status. Other recipients are unaffected. Shipment-level status reflects partial completion. Return/re-attempt policy applies only to the refused recipient."
    },
    {
      "scenario": "Two recipients on the same shipment have conflicting delivery preferences (e.g., one requires morning delivery, one requires evening)",
      "expected_behavior": "The system must support independent delivery scheduling per recipient. If the shipment is a single physical package being split, this may not be possible — the physical-vs-logical shipment distinction must be resolved."
    },
    {
      "scenario": "A multi-recipient shipment is sent to an external partner API that only understands single-recipient format",
      "expected_behavior": "The API adapter must apply a documented transformation. Options: send N separate payloads (one per recipient), send only a primary recipient, or reject the call with a clear error. This MUST be explicitly decided, not silently truncated."
    },
    {
      "scenario": "Adding a recipient to a shipment that is already in-transit",
      "expected_behavior": "Business must define whether recipients are mutable after shipment leaves origin. In most logistics domains, the recipient list is locked at dispatch. If mutability is allowed, it has major operational implications for routing and courier instructions."
    },
    {
      "scenario": "Cancellation of one recipient on a multi-recipient shipment",
      "expected_behavior": "Partial cancellation must be supported. If the last recipient is cancelled, does the entire shipment cancel? This maps back to BR-1 — a shipment cannot have zero recipients."
    },
    {
      "scenario": "Billing: who pays for a multi-recipient shipment?",
      "expected_behavior": "Current billing model likely assumes 1 shipment = 1 delivery fee. Multi-recipient may require per-recipient pricing, a group rate, or sender-pays-all. Billing impact is not addressed in the spec."
    },
    {
      "scenario": "Notifications: who gets notified of shipment events?",
      "expected_behavior": "With single-recipient, all events go to one person. With multi-recipient, each recipient should only receive notifications about their own delivery, not the entire shipment. Notification routing must become recipient-scoped."
    }
  ],

  "business_impact": {
    "financial": "High. Multi-recipient shipments change the billing unit. If pricing is per-shipment, multi-recipient creates a loophole where senders bundle N deliveries into one fee. If pricing is per-recipient, existing single-recipient shipments must not see a price change. Revenue model must be explicitly updated before launch. Migration cost for 2M records is non-trivial but one-time.",
    "operational": "Very High. Courier workflows change fundamentally. A single-recipient shipment = one stop. Multi-recipient = multiple stops per shipment, requiring route optimization, partial delivery tracking, per-recipient POD capture, and split status management. Dispatch and tracking systems must be rearchitected, not just patched.",
    "user": "Medium-High. Senders gain flexibility (ship to multiple recipients in one action). Recipients gain personalized delivery preferences. However, recipient-facing tracking becomes more complex — a recipient should see only their delivery, not the full multi-stop journey. UX for both sender and recipient must be redesigned.",
    "risk": "High. (1) Partner API breakage is the most immediate risk — silent data truncation could cause misdeliveries. (2) Data migration of 2M records must be zero-downtime and reversible. (3) The spec is underspecified on shipment status model, billing, and recipient mutability — shipping without resolving these creates undefined behavior in production. (4) Domain model change at the aggregate root level affects every downstream consumer.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "New capability to address multiple recipients per shipment. Must understand new pricing model. Existing workflows for single-recipient must not break." },
      { "group": "Recipients", "impact": "Gain delivery preferences. Tracking and notifications must be scoped to their delivery only. Must not see other recipients' data (privacy)." },
      { "group": "Couriers/Drivers", "impact": "Major workflow change. Multi-stop shipments require new routing logic, per-recipient delivery confirmation, and handling of partial failures." },
      { "group": "External API Partners", "impact": "Breaking change. Partners consuming single-recipient payloads will fail or misinterpret multi-recipient data. Requires versioned API or adapter layer with explicit migration plan." },
      { "group": "Customer Support", "impact": "Must handle queries about partial deliveries, per-recipient status, and new preference-related issues. Training and tooling updates required." },
      { "group": "Finance/Billing Team", "impact": "Pricing model must be redefined. Invoicing, refunds, and cost allocation all change when a shipment can have N recipients." },
      { "group": "Operations/Dispatch", "impact": "Routing algorithms, load planning, and SLA calculations all change. A multi-recipient shipment has a different operational profile than a single-recipient one." }
    ]
  },

  "confidence": {
    "level": 42,
    "reasoning": "The spec defines the structural change (1:1 → 1:N) but leaves critical operational semantics undefined. Shipment status model for partial delivery, billing implications, partner API transformation strategy, recipient mutability after dispatch, and the physical-vs-logical shipment distinction are all unresolved. These are not implementation details — they are business-defining decisions that change what 'correct' means. Without them, acceptance criteria for key flows cannot be fully specified.",
    "high_confidence_areas": [
      "The 1:N structural relationship is clearly stated and well-understood",
      "Backward compatibility for existing 2M records is a hard requirement",
      "Delivery preferences are per-recipient, not per-shipment",
      "At-least-one-recipient invariant is unambiguous",
      "External partner API risk is concrete and immediate"
    ],
    "low_confidence_areas": [
      "Shipment-level status model when recipients are in different delivery states",
      "Billing and pricing model for multi-recipient shipments",
      "Partner API transformation strategy for multi-recipient data",
      "Whether recipients can be added/removed after shipment dispatch",
      "Whether a 'primary recipient' concept exists",
      "Physical vs logical shipment — is this one package to many addresses or many packages grouped?",
      "Privacy model — can recipient A see recipient B's data?"
    ],
    "assumptions": [
      "The existing Recipient fields (name, address, phone) remain required for all recipients under the new model",
      "Delivery preferences are a new, optional concept — not retrofitted onto existing data",
      "The migration is additive (wrapping single recipient in a collection) not destructive",
      "External partners cannot be broken without notice — an adapter or versioned API is required",
      "This is a multi-destination shipment, not a multi-package-to-same-address scenario"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what a Shipment's status means when recipients are in different delivery states. Is the shipment 'delivered' when the first recipient receives goods, when all do, or is there a new 'partially delivered' state? This fundamentally changes tracking, SLAs, and partner reporting.",
      "affected_stakeholders": ["Recipients", "Senders/Shippers", "Couriers/Drivers", "Operations/Dispatch", "External API Partners"],
      "options": [
        "A: Shipment status is the minimum of all recipient statuses (shipment is 'delivered' only when ALL recipients are delivered)",
        "B: Shipment status is replaced by per-recipient statuses, with an aggregate computed status",
        "C: Shipment retains a simple status but adds a per-recipient status sub-model"
      ],
      "recommendation": "Option C — preserves backward compatibility for consumers that expect a single status while enabling granular tracking. But this needs explicit product definition."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not address the billing model. A multi-recipient shipment that costs the same as a single-recipient one creates a revenue leak. A per-recipient fee changes the pricing contract for all senders.",
      "affected_stakeholders": ["Finance/Billing Team", "Senders/Shippers"],
      "options": [
        "A: Per-recipient pricing (base + N*per_recipient_fee)",
        "B: Flat shipment fee regardless of recipient count",
        "C: Tiered pricing based on recipient count brackets"
      ],
      "recommendation": "Option A is the industry standard for multi-drop deliveries. But this is a business decision that must come from product/finance, not engineering."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not define the partner API transformation strategy for multi-recipient shipments. Silent truncation to the first recipient would cause misdeliveries. This is the highest immediate risk.",
      "affected_stakeholders": ["External API Partners", "Recipients", "Operations/Dispatch"],
      "options": [
        "A: Fan-out — send one API call per recipient, each looking like a single-recipient shipment",
        "B: API versioning — v1 only supports single-recipient (reject multi), v2 supports multi",
        "C: Adapter with primary-recipient extraction and a separate notification for additional recipients"
      ],
      "recommendation": "Option B with a migration timeline. v1 rejects multi-recipient with a clear error. v2 is the new contract. Fan-out (Option A) risks creating phantom shipments in partner systems."
    },
    {
      "type": "ambiguity",
      "description": "Is a multi-recipient Shipment one physical package going to multiple addresses (split shipment), or multiple packages grouped under one shipment ID? This distinction affects routing, weight calculations, customs declarations, and courier workflows fundamentally.",
      "affected_stakeholders": ["Couriers/Drivers", "Operations/Dispatch", "Senders/Shippers"],
      "options": [
        "A: One package, multiple stops — goods are split at a hub or delivered sequentially",
        "B: Multiple packages, one logical shipment — each recipient gets their own parcel",
        "C: Configurable per shipment"
      ],
      "recommendation": "This must be clarified before implementation. Option B is more common in logistics (multi-drop). Option A implies a completely different fulfillment model. Cannot proceed without this answer."
    },
    {
      "type": "missing_context",
      "description": "Delivery preferences are introduced but not enumerated. What preferences are supported? Time windows? Signature requirements? Safe-place authorization? Contactless delivery? Without a defined preference schema, this feature cannot be implemented or tested.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Product Team"],
      "options": [
        "A: Define a fixed enum of supported preferences now",
        "B: Use a flexible key-value model that can be extended",
        "C: Start with a minimal set (time window + signature required) and expand"
      ],
      "recommendation": "Option C — ship with a minimal, well-defined preference set. Flexible key-value models become unvalidatable. But the minimal set must be explicitly defined by product."
    }
  ],

  "rejection_reasons": []
}

